from dataclasses import dataclass
from typing import List, Dict
from enum import Enum

class Maturity(Enum):
    RESEARCH = 1
    PILOT = 2
    PRODUCTION = 3

@dataclass
class Initiative:
    institution: str
    application: str
    maturity: Maturity
    investment_millions: float

class InitiativeTracker:
    def __init__(self):
        self.initiatives: List[Initiative] = []

    def add_initiative(self, initiative: Initiative):
        self.initiatives.append(initiative)

    def total_investment(self) -> float:
        return sum(i.investment_millions for i in self.initiatives)

    def by_application(self) -> Dict[str, List[Initiative]]:
        result = {}
        for i in self.initiatives:
            if i.application not in result:
                result[i.application] = []
            result[i.application].append(i)
        return result

    def maturity_summary(self) -> Dict[str, int]:
        summary = {m.name: 0 for m in Maturity}
        for i in self.initiatives:
            summary[i.maturity.name] += 1
        return summary

