from dataclasses import dataclass
from typing import List, Dict

@dataclass
class Institution:
    name: str
    investment: float
    team_size: int
    publications: int
    partnerships: int

class CompetitiveScorer:
    def __init__(self):
        self.institutions: List[Institution] = []

    def add_institution(self, inst: Institution):
        self.institutions.append(inst)

    def calculate_score(self, inst: Institution) -> float:
        if not self.institutions:
            return 0
        max_inv = max(i.investment for i in self.institutions) or 1
        max_team = max(i.team_size for i in self.institutions) or 1
        max_pub = max(i.publications for i in self.institutions) or 1
        max_part = max(i.partnerships for i in self.institutions) or 1

        score = (
            0.30 * inst.investment / max_inv +
            0.25 * inst.team_size / max_team +
            0.25 * inst.publications / max_pub +
            0.20 * inst.partnerships / max_part
        )
        return round(score, 3)

    def rank_institutions(self) -> List[Dict]:
        rankings = []
        for inst in self.institutions:
            rankings.append({
                'name': inst.name,
                'score': self.calculate_score(inst)
            })
        return sorted(rankings, key=lambda x: x['score'], reverse=True)

