from dataclasses import dataclass
from typing import List, Dict

@dataclass
class UseCase:
    name: str
    classical_time_hours: float
    quantum_time_hours: float
    annual_runs: int
    hourly_value: float

class ValueCalculator:
    def __init__(self):
        self.use_cases: List[UseCase] = []

    def add_use_case(self, uc: UseCase):
        self.use_cases.append(uc)

    def speedup_factor(self, uc: UseCase) -> float:
        if uc.quantum_time_hours == 0:
            return float('inf')
        return uc.classical_time_hours / uc.quantum_time_hours

    def annual_time_savings(self, uc: UseCase) -> float:
        return (uc.classical_time_hours - uc.quantum_time_hours) * uc.annual_runs

    def annual_value(self, uc: UseCase) -> float:
        return self.annual_time_savings(uc) * uc.hourly_value

    def total_portfolio_value(self) -> float:
        return sum(self.annual_value(uc) for uc in self.use_cases)

