from dataclasses import dataclass
from typing import List, Dict, Optional

@dataclass
class Milestone:
    year: int
    phase: str
    capabilities: List[str]

class RoadmapBuilder:
    def __init__(self):
        self.milestones: List[Milestone] = []

    def add_milestone(self, milestone: Milestone):
        self.milestones.append(milestone)

    def get_phase_for_year(self, year: int) -> Optional[str]:
        applicable = [m for m in self.milestones if m.year <= year]
        if not applicable:
            return None
        return max(applicable, key=lambda m: m.year).phase

    def years_until_capability(self, capability: str, current_year: int = 2025) -> int:
        for m in sorted(self.milestones, key=lambda x: x.year):
            if capability.lower() in [c.lower() for c in m.capabilities]:
                return max(0, m.year - current_year)
        return -1

    def get_timeline(self) -> List[Dict]:
        return [
            {'year': m.year, 'phase': m.phase, 'capabilities': m.capabilities}
            for m in sorted(self.milestones, key=lambda x: x.year)
        ]

