from dataclasses import dataclass
from typing import Dict
import numpy as np

@dataclass
class QuantumInvestment:
    initial_cost: float
    annual_operating: float
    years_to_value: int
    annual_benefit: float
    investment_horizon: int

class ROIAnalyzer:
    def __init__(self, discount_rate: float = 0.10):
        self.discount_rate = discount_rate

    def _cash_flows(self, investment: QuantumInvestment) -> list:
        flows = [-investment.initial_cost]
        for year in range(1, investment.investment_horizon + 1):
            if year < investment.years_to_value:
                flows.append(-investment.annual_operating)
            else:
                flows.append(investment.annual_benefit - investment.annual_operating)
        return flows

    def calculate_npv(self, investment: QuantumInvestment) -> float:
        flows = self._cash_flows(investment)
        npv = 0
        for i, cf in enumerate(flows):
            npv += cf / (1 + self.discount_rate) ** i
        return npv

    def calculate_irr(self, investment: QuantumInvestment) -> float:
        flows = self._cash_flows(investment)
        for rate in np.arange(-0.5, 1.0, 0.001):
            npv = sum(cf / (1 + rate) ** i for i, cf in enumerate(flows))
            if abs(npv) < 0.01:
                return rate
        return np.nan

    def payback_period(self, investment: QuantumInvestment) -> float:
        cumulative = -investment.initial_cost
        for year in range(1, investment.investment_horizon + 1):
            if year < investment.years_to_value:
                cumulative -= investment.annual_operating
            else:
                cumulative += investment.annual_benefit - investment.annual_operating
            if cumulative >= 0:
                return year
        return float('inf')

    def full_analysis(self, investment: QuantumInvestment) -> Dict:
        return {
            'npv': self.calculate_npv(investment),
            'irr': self.calculate_irr(investment),
            'payback_years': self.payback_period(investment),
            'total_investment': investment.initial_cost + investment.annual_operating * investment.investment_horizon,
            'total_benefit': investment.annual_benefit * (investment.investment_horizon - investment.years_to_value + 1)
        }
